  1→import dayjs from "dayjs";
  2→import utc from "dayjs/plugin/utc.js";
  3→import timezone from "dayjs/plugin/timezone.js";
  4→import pluginRSS from "@11ty/eleventy-plugin-rss";
  5→import pluginWebc from "@11ty/eleventy-plugin-webc";
  6→
  7→dayjs.extend(utc);
  8→dayjs.extend(timezone);
  9→dayjs.tz.setDefault("America/New_York");
 10→
 11→export default function (conf) {
 12→  conf.addPlugin(pluginRSS);
 13→  conf.addPlugin(pluginWebc, {
 14→    components: "src/_components/**/*.webc",
 15→  });
 16→
 17→  conf.addFilter("groupByYear", (posts) => {
 18→    const grouped = new Map();
 19→    for (const post of posts) {
 20→      const year = dayjs(post.data.date).year();
 21→      if (!grouped.has(year)) grouped.set(year, []);
 22→      grouped.get(year).push(post);
 23→    }
 24→    return [...grouped].map(([year, posts]) => ({ year, posts }));
 25→  });
 26→
 27→  conf.addFilter("flattenBooks", (groups) => {
 28→    return groups.flatMap((group) =>
 29→      group.books.map((book) => ({ ...book, year: group.year }))
 30→    );
 31→  });
 32→
 33→  conf.addFilter("totalWordCount", (posts) => {
 34→    return posts.reduce((total, post) => {
 35→      const raw = post.rawInput || "";
 36→      const text = raw
 37→        .replace(/^---[\s\S]*?---/, "")
 38→        .replace(/```[\s\S]*?```/g, "")
 39→        .replace(/<pre[\s>][\s\S]*?<\/pre>/gi, "")
 40→        .replace(/<[^>]+>/g, "")
 41→        .replace(/\s+/g, " ")
 42→        .trim();
 43→      return total + (text ? text.split(" ").length : 0);
 44→    }, 0).toLocaleString("en-US");
 45→  });
 46→
 47→  conf.addFilter("plainTextPreview", (html, max = 290) => {
 48→    const text = html
 49→      .replace(/<[^>]+>/g, "")
 50→      .replace(/\s+/g, " ")
 51→      .trim();
 52→    if (text.length <= max) return text;
 53→    const truncated = text.slice(0, max);
 54→    const lastSpace = truncated.lastIndexOf(" ");
 55→    return truncated.slice(0, lastSpace);
 56→  });
 57→
 58→  conf.addFilter("dateFormat", (dateStr, format) => {
 59→    return dayjs(dateStr).format(format);
 60→  });
 61→
 62→  conf.addFilter("getRSSDate", (dateStr) => {
 63→    // Parse the date string in UTC and set to noon
 64→    // This prevents the date from shifting to the previous day in feed readers
 65→    let date = dayjs.utc(dateStr).hour(12).toISOString().split(".");
 66→
 67→    // Remove milliseconds (RFC 3339 requirement)
 68→    date.pop();
 69→
 70→    return date.join("") + "Z";
 71→  });
 72→
 73→  conf.addPassthroughCopy("src/manifest.webmanifest");
 74→  conf.addPassthroughCopy("src/keybase.txt");
 75→  conf.addPassthroughCopy("src/robots.txt");
 76→  conf.addPassthroughCopy("src/humans.txt");
 77→  conf.addPassthroughCopy("src/llms.txt");
 78→  conf.addPassthroughCopy("src/rss.xml");
 79→  conf.addPassthroughCopy("src/.well-known");
 80→  conf.addPassthroughCopy("src/fonts");
 81→  conf.addPassthroughCopy("src/images");
 82→  conf.addPassthroughCopy("src/videos");
 83→  conf.addPassthroughCopy("src/css");
 84→  conf.addPassthroughCopy("src/js");
 85→
 86→  conf.addCollection("nowUpdates", (collections) => {
 87→    return collections
 88→      .getFilteredByTag("now-update")
 89→      .sort((a, b) => b.date - a.date)
 90→      .map((update) => {
 91→        const date = dayjs(update.data.date);
 92→        update.data.date = date.format("YYYY-MM-DD");
 93→        update.data.dateHuman = date.format("MMMM D, YYYY");
 94→        return update;
 95→      });
 96→  });
 97→
 98→  conf.addCollection("posts", (collections) => {
 99→    return collections
100→      .getFilteredByTag("post")
101→      .sort((a, b) => b.date - a.date)
102→      .map((post) => {
103→        const date = dayjs(post.data.date);
104→        post.data.date = date.format("YYYY-MM-DD");
105→        post.data.dateHuman = date.format("MMMM D, YYYY");
106→        return post;
107→      });
108→  });
109→
110→  conf.addWatchTarget("src/_components/");
111→
112→  conf.setServerOptions({
113→    domDiff: false,
114→  });
115→
116→  return {
117→    dir: {
118→      input: "src",
119→      output: "dist",
120→    },
121→    markdownTemplateEngine: false,
122→  };
123→}
